/// <summary>
/// Extension of the <c>SalesAgreement</c> form for the ETGSPAIN model.
/// </summary>
[ExtensionOf(FormStr(SalesAgreement))]
final class SalesAgreement_Form_ETGSPAIN_Extension
{
}

Method.Source:
/// <summary>
/// Extension of the <c>init</c> method for the ETGSPAIN model.
/// </summary>
/// <remarks>
/// This code is used to show or hide features in Spanish companies.
/// </remarks>
public void init()
{
    next init();
    NoYesId currentCompanyIsSpanishCompany  = CurrentCompanyIsSpanishCompany();

    this.design().controlName(formControlStr(SalesAgreement, ALine_AgreementLineQuantityCommitment_ETGSPAINOverDeliveryPct)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesAgreement, ALine_AgreementLineQuantityCommitment_ETGSPAINUnderDeliveryPct)).visible(currentCompanyIsSpanishCompany);

    this.design().controlName(formControlStr(SalesAgreement, ALine_ETGSPAINLineCode)).visible(currentCompanyIsSpanishCompany);

    this.design().controlName(formControlStr(SalesAgreement, ETGSPAINPurchSalesAgreementQuotaDialog)).visible(currentCompanyIsSpanishCompany);

    this.design().controlName(formControlStr(SalesAgreement, SalesAgreementHeader_ETGSPAINAgreementOperationId1)).visible(currentCompanyIsSpanishCompany);

    this.design().controlName(formControlStr(SalesAgreement, ETGSPAINAgreementQuota)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesAgreement, SalesAgreementHeader_ETGSPAINPurchHasAgreementQuotas)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesAgreement, SalesAgreementHeader_ETGSPAINPurchAgreementQuotaPeriods)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesAgreement, SalesAgreementHeader_ETGSPAINPurchAgreementQuotaFromDate)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesAgreement, SalesAgreementHeader_ETGSPAINPurchAgreementQuotaToDate)).visible(currentCompanyIsSpanishCompany);

    this.design().controlName(formControlStr(SalesAgreement, ETGSPAINCountryRegionIdOrigin)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesAgreement, SalesAgreementHeader_ETGSPAINPurchCountryRegionIdOrigin)).visible(currentCompanyIsSpanishCompany);

    this.design().controlName(formControlStr(SalesAgreement, SalesAgreementHeader_ETGSPAINPurchAgreementType)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesAgreement, SalesAgreementHeader_ETGSPAINAgreementOperationId)).visible(currentCompanyIsSpanishCompany);

    this.design().controlName(formControlStr(SalesAgreement, ETGSPAINPorts)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesAgreement, ETGSPAINPorts_ETGSPAINPurchLoadPortId)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesAgreement, ETGSPAINPorts_ETGSPAINPurchUnloadPortId)).visible(currentCompanyIsSpanishCompany);

    this.design().controlName(formControlStr(SalesAgreement, ETGSPAINExecutionDates)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesAgreement, ETGSPAINExecutionDates_ETGSPAINPurchExecutionDueDate)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesAgreement, ETGSPAINExecutionDates_ETGSPAINPurchExecutionFromDate)).visible(currentCompanyIsSpanishCompany);

    this.design().controlName(formControlStr(SalesAgreement, ETGSPAINTrackingDimensions)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesAgreement, ETGSPAINTrackingDimensions_InventGtdId_RU)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesAgreement, ETGSPAINTrackingDimensions_InventDimension1)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesAgreement, ETGSPAINTrackingDimensions_inventSerialId)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesAgreement, ETGSPAINTrackingDimensions_InventProfileId_RU)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesAgreement, ETGSPAINTrackingDimensions_InventOwnerId_RU)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesAgreement, ETGSPAINTrackingDimensions_inventBatchId)).visible(currentCompanyIsSpanishCompany);

    this.design().controlName(formControlStr(SalesAgreement, SalesAgreementHeader_ETGSPAINPurchExecutionDueDate)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesAgreement, SalesAgreementHeader_ETGSPAINPurchInvoiceType)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesAgreement, SalesAgreementHeader_ETGSPAINPurchExecutionFromDate)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesAgreement, SalesAgreementHeader_ETGSPAINPurchPlateDaysNumber)).visible(currentCompanyIsSpanishCompany);

    if (currentCompanyIsSpanishCompany == NoYes::Yes)
    {
        AgreementHeaderDefault_DS.object(fieldNum(AgreementHeaderDefault, DeliveryTerm)).mandatory(true); 
        this.design().controlName(formControlStr(SalesAgreement, SalesAgreementHeader_ETGSPAINPurchHasAgreementQuotas)).enabled(false);
    }

    this.design().controlName(formControlStr(SalesAgreement, ProFormaButton)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesAgreement, ProfomaRpt)).visible(!currentCompanyIsSpanishCompany);

    this.design().controlName(formControlStr(PurchAgreement, ButtonConfirmationETG)).visible(!currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(PurchAgreement, ButtonConfirmation)).visible(currentCompanyIsSpanishCompany);
}
